const query = $input.first().json.query || $input.first().json;
const code = query.code;
const state = query.state;

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const N8N_PUBLIC_URL = '{{N8N_URL}}';
const TELEGRAM_BOT_TOKEN = '{{TELEGRAM_BOT_TOKEN}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json'
};

// Validate inputs
if (!code || !state) {
  return [{ json: { success: false, error: 'Missing code or state parameter.' } }];
}

// 1. Validate state against oauth_states table
let stateRow;
try {
  const rows = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/oauth_states?state=eq.' + state + '&select=*',
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
  });
  if (!rows || rows.length === 0) {
    return [{ json: { success: false, error: 'Invalid or unknown state parameter.' } }];
  }
  stateRow = rows[0];
} catch(e) {
  return [{ json: { success: false, error: 'State validation failed: ' + e.message } }];
}

if (stateRow.used) {
  return [{ json: { success: false, error: 'This authorization link has already been used.' } }];
}

if (new Date(stateRow.expires_at) < new Date()) {
  return [{ json: { success: false, error: 'This authorization link has expired. Please request a new one.' } }];
}

// 2. Mark state as used immediately (prevent replay)
try {
  await helpers.httpRequest({
    method: 'PATCH',
    url: SUPABASE_URL + '/rest/v1/oauth_states?state=eq.' + state,
    headers: { ...pgHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({ used: true })
  });
} catch(e) { /* best effort */ }

// 3. Read client_id + client_secret from template_credentials
let clientId, clientSecret;
try {
  const creds = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&select=cred_key,cred_value',
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
  });
  const credMap = {};
  for (const c of creds) credMap[c.cred_key] = c.cred_value;
  clientId = credMap.client_id;
  clientSecret = credMap.client_secret;
} catch(e) {
  return [{ json: { success: false, error: 'Could not read OAuth credentials: ' + e.message } }];
}

if (!clientId || !clientSecret) {
  return [{ json: { success: false, error: 'Google OAuth client_id or client_secret not found. Please enter them first.' } }];
}

// 4. Exchange authorization code for tokens
let tokenData;
try {
  const redirectUri = N8N_PUBLIC_URL + '/webhook/oauth-callback';
  tokenData = await helpers.httpRequest({
    method: 'POST',
    url: 'https://oauth2.googleapis.com/token',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: 'grant_type=authorization_code'
      + '&code=' + encodeURIComponent(code)
      + '&redirect_uri=' + encodeURIComponent(redirectUri)
      + '&client_id=' + encodeURIComponent(clientId)
      + '&client_secret=' + encodeURIComponent(clientSecret)
  });
} catch(e) {
  return [{ json: { success: false, error: 'Token exchange failed: ' + e.message } }];
}

if (tokenData.error) {
  return [{ json: { success: false, error: 'Google token error: ' + (tokenData.error_description || tokenData.error) } }];
}

// 5. Store tokens in template_credentials (UPSERT via DELETE+INSERT)
const tokenExpiry = new Date(Date.now() + (tokenData.expires_in - 60) * 1000).toISOString();

const toStore = [
  ['access_token', tokenData.access_token],
  ['refresh_token', tokenData.refresh_token],
  ['token_expiry', tokenExpiry],
  ['scopes', stateRow.scopes]
];

for (const [key, value] of toStore) {
  if (!value) continue;
  try {
    await helpers.httpRequest({
      method: 'DELETE',
      url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&cred_key=eq.' + key,
      headers: { ...pgHeaders, 'Prefer': 'return=minimal' }
    });
    await helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/rest/v1/template_credentials',
      headers: { ...pgHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        template_id: 'google-oauth',
        cred_key: key,
        cred_value: value
      })
    });
  } catch(e) {
    return [{ json: { success: false, error: 'Failed to store ' + key + ': ' + e.message } }];
  }
}

// 6. Notify user via Telegram (if chat_id available)
if (stateRow.chat_id && TELEGRAM_BOT_TOKEN !== '{{TELEGRAM_BOT_TOKEN}}') {
  try {
    await helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + TELEGRAM_BOT_TOKEN + '/sendMessage',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        chat_id: stateRow.chat_id,
        text: '\u2705 Google-Autorisierung erfolgreich abgeschlossen! Die angefragten Berechtigungen sind jetzt aktiv.',
        parse_mode: 'HTML'
      })
    });
  } catch(e) { /* non-critical */ }
}

// Success
return [{ json: { success: true, template_id: stateRow.template_id } }];
